import React from 'react';
import ReactDOM, { render } from 'react-dom';
import './index.css';
function homePage(){
    const name = (
        <div id = "main">
            <head>
                <title>Sign In/Sign UP</title>
            </head>
            <div id = "signin">
            <body>
                <LoginInfo/>
                <Username/>
                <Password/>
                <Signup/>
                <EmailAddress/>
                <SignUpPassword/>
                <br></br>
                <Submit/>
            </body>
            </div>
        </div>
    );
    ReactDOM.render(name, document.getElementById('root'))
}
setInterval(homePage, 1000)
